{"Id":"a00gL00000gVdZZQA0","formula":"const markers = $map.getSelectionIds().map(id => $map.getMarker(id));
if (markers.length !== 1) {
    return { html: '<div class="alert alert-warning">Veuillez sélectionner exactement un point pour l\'analyse.</div>' };
}

const sourceMarker = markers[0];
let center = sourceMarker.latlng;
if (!center) {
    const bounds = $map.getMarkerBounds($map.getMarkerId(sourceMarker));
    center = bounds.getCenter().toJSON();
}

console.info('Démarrage analyse de voisinage complète au point:', center);

if (window._analysisLayer) {
    window._analysisLayer.forEach(obj => obj.setMap(null));
}
window._analysisLayer = [];

const radius = 200;
const sourcePoint = turf.point([center.lng, center.lat]);

// 1. Cercle d'emprise
const circle = new google.maps.Circle({
    strokeColor: '#007bff', strokeOpacity: 0.3, strokeWeight: 1, fillColor: '#007bff', fillOpacity: 0.05,
    map: $map.getMapObject(), center: center, radius: radius, clickable: false
});
window._analysisLayer.push(circle);
$map.fitBounds(circle.getBounds());

// 2. Définition des catégories
const categories = {
    habitation: { label: 'Habitation', color: '#28a745', tags: ['house', 'apartments', 'residential', 'detached', 'terrace', 'dormitory', 'hotel'] },
    commercial: { label: 'Commerce', color: '#007bff', tags: ['retail', 'commercial', 'office', 'supermarket', 'kiosk'] },
    industrial: { label: 'Industrie', color: '#6f42c1', tags: ['industrial', 'warehouse', 'manufacture', 'factory'] },
    public: { label: 'Public', color: '#ffc107', tags: ['school', 'university', 'hospital', 'church', 'civic', 'public', 'kindergarten', 'government'] }
};

const getCategory = (tag) => {
    if (categories.commercial.tags.includes(tag)) return 'commercial';
    if (categories.industrial.tags.includes(tag)) return 'industrial';
    if (categories.public.tags.includes(tag)) return 'public';
    return 'habitation'; 
};

// 3. Requête Overpass (Bâtiments + Végétation complète)
const overpassQuery = `[out:json][timeout:30];(
  way["building"](around:${radius},${center.lat},${center.lng});
  way["landuse"~"forest|orchard|village_green"](around:${radius},${center.lat},${center.lng});
  way["natural"~"wood|scrub|tree_row"](around:${radius},${center.lat},${center.lng});
  way["leisure"~"park|garden"](around:${radius},${center.lat},${center.lng});
);out body;>;out skel qt;`;

const response = await fetch(`https://overpass-api.de/api/interpreter?data=${encodeURIComponent(overpassQuery)}`);
if (!response.ok) return { html: '<div class="alert alert-danger font-weight-bold">Le service Overpass est momentanément indisponible.</div>' };

const osmData = await response.json();
const nodes = new Map();
osmData.elements.filter(e => e.type === 'node').forEach(n => nodes.set(n.id, [n.lon, n.lat]));

const buildingFeatures = [];
const vegetationFeatures = [];

osmData.elements.filter(e => e.type === 'way' && e.nodes).forEach(w => {
    const coords = w.nodes.map(nodeId => nodes.get(nodeId)).filter(c => !!c);
    if (coords.length > 2) {
        const poly = turf.polygon([coords], { id: w.id, tags: w.tags || {} });
        if (w.tags?.building) buildingFeatures.push(poly); else vegetationFeatures.push(poly);
    }
});

// Dessiner la végétation
vegetationFeatures.forEach(veg => {
    window._analysisLayer.push(new google.maps.Polygon({
        paths: veg.geometry.coordinates[0].map(c => ({ lng: c[0], lat: c[1] })),
        strokeColor: '#19692c', strokeOpacity: 0.5, strokeWeight: 1, fillColor: '#19692c', fillOpacity: 0.2, map: $map.getMapObject(), zIndex: 1
    }));
});

const stats = {};
Object.keys(categories).forEach(k => stats[k] = { total: 0, visible: 0, obstructed: 0 });

// 4. Calcul de co-visibilité
buildingFeatures.forEach(building => {
    const bType = getCategory(building.properties.tags.building);
    const bCenter = turf.centroid(building);
    const losLine = turf.lineString([sourcePoint.geometry.coordinates, bCenter.geometry.coordinates]);

    let isObstructed = false;
    for (const other of buildingFeatures) {
        if (other.properties.id === building.properties.id) continue;
        if (turf.lineIntersect(losLine, other).features.length > 0) { isObstructed = true; break; }
    }
    if (!isObstructed) {
        for (const veg of vegetationFeatures) {
            if (turf.lineIntersect(losLine, veg).features.length > 0) { isObstructed = true; break; }
        }
    }

    stats[bType].total++;
    if (isObstructed) stats[bType].obstructed++; else stats[bType].visible++;

    // Dessin Bâtiment
    window._analysisLayer.push(new google.maps.Polygon({
        paths: building.geometry.coordinates[0].map(c => ({ lng: c[0], lat: c[1] })),
        strokeColor: categories[bType].color, strokeOpacity: 0.8, strokeWeight: 1, fillColor: categories[bType].color, fillOpacity: 0.4, map: $map.getMapObject(), zIndex: 2
    }));

    // Dessin Ligne de vue
    window._analysisLayer.push(new google.maps.Polyline({
        path: [center, { lat: bCenter.geometry.coordinates[1], lng: bCenter.geometry.coordinates[0] }],
        strokeColor: isObstructed ? '#dc3545' : '#28a745', strokeOpacity: 0.5, strokeWeight: 1, map: $map.getMapObject(), zIndex: 3
    }));
});

const chartId = 'chart-' + Math.random().toString(36).substr(2, 9);
requestAnimationFrame(() => {
    new Chart(document.getElementById(chartId), {
        type: 'bar', data: {
            labels: [''],
            datasets: Object.entries(categories).map(([key, cat]) => ({
                label: cat.label, data: [stats[key].total], backgroundColor: cat.color, barThickness: 22
            }))
        },
        options: {
            indexAxis: 'y', maintainAspectRatio: false,
            scales: { x: { stacked: true, display: false }, y: { stacked: true, display: false } },
            plugins: { legend: { display: false }, tooltip: { enabled: true } }
        }
    });
});

return {
    html: `
        <div class="card border-0 shadow-sm">
            <div class="card-header bg-white py-2 font-weight-bold">Analyse de Voisinage et Co-visibilité</div>
            <div class="card-body p-3">
                <div class="mb-2 d-flex flex-wrap justify-content-center">
                    ${Object.values(categories).map(c => `<small class="mr-2 text-dark"><span style="width:8px;height:8px;background:${c.color};display:inline-block;" class="mr-1"></span>${c.label}</small>`).join('')}
                    <small class="text-dark"><span style="width:8px;height:8px;background:#19692c;display:inline-block;" class="mr-1"></span>Végétation</small>
                </div>
                <div style="height: 30px;" class="mb-3"><canvas id="${chartId}"></canvas></div>

                <table class="table table-sm table-borderless mb-0" style="font-size: 0.8rem;">
                    <thead class="text-muted border-bottom">
                        <tr>
                            <th>Catégorie</th>
                            <th class="text-center">Total</th>
                            <th class="text-center text-success">Visible</th>
                            <th class="text-center text-danger">Obstrué</th>
                        </tr>
                    </thead>
                    <tbody class="text-dark">
                        ${Object.entries(categories).map(([key, cat]) => `
                            <tr>
                                <td class="font-weight-bold" style="color:${cat.color}">${cat.label}</td>
                                <td class="text-center font-weight-bold">${stats[key].total}</td>
                                <td class="text-center">${stats[key].visible}</td>
                                <td class="text-center">${stats[key].obstructed}</td>
                            </tr>
                        `).join('')}
                    </tbody>
                </table>
            </div>
            <div class="card-footer bg-light p-2 text-center small font-weight-bold">
                TAUX DE VISIBILITÉ DIRECTE : ${Math.round((Object.values(stats).reduce((a,b)=>a+b.visible,0) / (buildingFeatures.length || 1)) * 100)}%
            </div>
        </div>
    `,
    data: stats,
    reset: () => { if (window._analysisLayer) window._analysisLayer.forEach(o => o.setMap(null)); }
};","description":"Analyse géospatiale du voisinage immédiat (200m). Cette analyse identifie les types de bâtiments et les zones de végétation dense. Elle calcule la co-visibilité en testant si chaque structure est masquée par un obstacle physique (autre bâtiment ou végétation). Les résultats sont présentés par catégorie (Habitation, Commerce, Industrie, Public).","title":"Voisinage et Co-visibilité","output":"{
  "habitation": { "total": "number", "visible": "number", "obstructed": "number" },
  "commercial": { "total": "number", "visible": "number", "obstructed": "number" },
  "industrial": { "total": "number", "visible": "number", "obstructed": "number" },
  "public": { "total": "number", "visible": "number", "obstructed": "number" }
}"}
